use serde::{Deserialize, Serialize};

/// What kind of dice sides
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub enum DiceSides {
    Standard(u32),  // d20, d6, etc.
    Fate,           // dF (-1, 0, +1) - Story 2 implements rolling
}

/// Modifiers applied to dice rolls
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub enum Modifier {
    Add(i32),
    Subtract(i32),
    KeepHighest(u32),
    KeepLowest(u32),
    DropHighest(u32),
    DropLowest(u32),
}

/// Parsed dice expression (output of parser)
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct DiceExpression {
    pub count: u32,               // number of dice (default 1)
    pub sides: DiceSides,         // die type
    pub modifiers: Vec<Modifier>, // keep/drop/add/subtract
    pub exploding: bool,          // ! suffix - Story 2 implements
}

/// Chain of explosions for a single die (Story 2 uses this)
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct ExplosionChain {
    pub values: Vec<i32>,  // e.g., [6, 6, 4]
    pub total: i32,        // sum of chain
}

/// Result of rolling dice (output of engine)
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct RollResult {
    pub expression: DiceExpression,      // what was rolled
    pub rolls: Vec<i32>,                 // individual die values
    pub kept: Vec<i32>,                  // dice kept after keep/drop
    pub dropped: Vec<i32>,               // dice dropped
    pub modifier_total: i32,             // sum of +/- modifiers
    pub total: i32,                      // final result
    pub explosions: Vec<ExplosionChain>, // for exploding dice (Story 2)
    pub fate_ladder: Option<String>,     // for fate dice (Story 2)
}

/// Error types for parsing and rolling
#[derive(Debug, Clone, thiserror::Error)]
pub enum DiceError {
    #[error("Parse error: {0}")]
    ParseError(String),
    #[error("Invalid dice notation: {0}")]
    InvalidNotation(String),
    #[error("Roll error: {0}")]
    RollError(String),
}
```

