// src/output.rs
use crate::types::RollResult;

/// Format roll result for display
/// Example: "🎲 Rolling: 2d6+3 → [4] [2] + 3 = 9"
/// Dropped dice shown with ~: "🎲 Rolling: 4d6dl1 → [6] [5] [4] ~[2]~ = 15"
pub fn format_roll(result: &RollResult) -> String {
    let dice_str = format_dice(&result.rolls, &result.kept, &result.dropped);
    let mod_str = format_modifier(result.modifier_total);

    format!(
        "🎲 Rolling: {} → {} {} = {}",
        format_expression(&result.expression),
        dice_str,
        mod_str,
        result.total
    )
}

