### Main Entry Point (Minimal for Story 1)

```rust
// src/main.rs
use sage_dice::{parse, DiceEngine, format_roll};

fn main() {
    // Story 1: minimal CLI - just parse notation from arg
    let args: Vec<String> = std::env::args().collect();

    if args.len() < 2 {
        eprintln!("Usage: sage-dice <notation>");
        eprintln!("Example: sage-dice 2d6+3");
        std::process::exit(1);
    }

    let notation = &args[1];

    match parse(notation) {
        Ok(expr) => {
            let mut engine = DiceEngine::new();
            match engine.roll(&expr) {
                Ok(result) => println!("{}", format_roll(&result)),
                Err(e) => {
                    eprintln!("Roll error: {}", e);
                    std::process::exit(1);
                }
            }
        }
        Err(e) => {
            eprintln!("Parse error: {}", e);
            std::process::exit(1);
        }
    }
}
```

