// tests/parser_test.rs
use sage_dice::parser::parse;
use sage_dice::types::{DiceSides, Modifier};

// === Basic Notation ===

#[test]
fn test_parse_simple_d20() {
    let expr = parse("d20").unwrap();
    assert_eq!(expr.count, 1);
    assert_eq!(expr.sides, DiceSides::Standard(20));
    assert!(expr.modifiers.is_empty());
    assert!(!expr.exploding);
}

#[test]
fn test_parse_2d6() {
    let expr = parse("2d6").unwrap();
    assert_eq!(expr.count, 2);
    assert_eq!(expr.sides, DiceSides::Standard(6));
}

#[test]
fn test_parse_with_modifier() {
    let expr = parse("2d6+3").unwrap();
    assert_eq!(expr.count, 2);
    assert_eq!(expr.sides, DiceSides::Standard(6));
    assert!(expr.modifiers.contains(&Modifier::Add(3)));
}

#[test]
fn test_parse_negative_modifier() {
    let expr = parse("1d20-2").unwrap();
    assert!(expr.modifiers.contains(&Modifier::Subtract(2)));
}

#[test]
fn test_parse_keep_highest() {
    let expr = parse("4d6kh3").unwrap();
    assert_eq!(expr.count, 4);
    assert!(expr.modifiers.contains(&Modifier::KeepHighest(3)));
}

#[test]
fn test_parse_keep_lowest() {
    let expr = parse("2d20kl1").unwrap();
    assert!(expr.modifiers.contains(&Modifier::KeepLowest(1)));
}

#[test]
fn test_parse_drop_lowest() {
    let expr = parse("4d6dl1").unwrap();
    assert!(expr.modifiers.contains(&Modifier::DropLowest(1)));
}

#[test]
fn test_parse_drop_highest() {
    let expr = parse("4d6dh1").unwrap();
    assert!(expr.modifiers.contains(&Modifier::DropHighest(1)));
}

#[test]
fn test_parse_case_insensitive() {
    let expr = parse("2D6+3").unwrap();
    assert_eq!(expr.count, 2);
    assert_eq!(expr.sides, DiceSides::Standard(6));
}

// === D9 Edge Cases ===

#[test]
fn test_parse_zero_dice_error() {
    // D9: 0d6 → Error (zero dice meaningless)
    assert!(parse("0d6").is_err());
}

#[test]
fn test_parse_zero_sides_error() {
    // D9: d0 → Error (zero-sided die impossible)
    assert!(parse("d0").is_err());
}

#[test]
fn test_parse_one_sided_allowed() {
    // D9: d1 → Allow (always rolls 1)
    let expr = parse("d1").unwrap();
    assert_eq!(expr.sides, DiceSides::Standard(1));
}

#[test]
fn test_parse_overflow_dice_error() {
    // D9: 999999d6 → Error (cap at 10000 dice)
    assert!(parse("999999d6").is_err());
}

#[test]
fn test_parse_overflow_sides_error() {
    // D9: d999999 → Error (cap at 10000 sides)
    assert!(parse("d999999").is_err());
}

#[test]
fn test_parse_at_limit_allowed() {
    // D9: 10000d10000 is the max allowed
    let expr = parse("10000d10000").unwrap();
    assert_eq!(expr.count, 10000);
    assert_eq!(expr.sides, DiceSides::Standard(10000));
}

#[test]
fn test_parse_keep_more_than_rolled() {
    // D9: 4d6kh10 → Keep all 4 (can't keep more than rolled)
    let expr = parse("4d6kh10").unwrap();
    assert_eq!(expr.count, 4);
    // Parser accepts it; engine will keep all 4
    assert!(expr.modifiers.contains(&Modifier::KeepHighest(10)));
}

#[test]
fn test_parse_keep_zero_error() {
    // D9: 4d6kh0 → Error (keep zero meaningless)
    assert!(parse("4d6kh0").is_err());
}

#[test]
fn test_parse_malformed_double_plus_error() {
    // D9: 2d6++3 → Error (malformed)
    assert!(parse("2d6++3").is_err());
}

#[test]
fn test_parse_incomplete_keep_error() {
    // D9: d20k → Error (incomplete keep modifier)
    assert!(parse("d20k").is_err());
}

// === General Invalid Input ===

#[test]
fn test_parse_invalid() {
    assert!(parse("invalid").is_err());
    assert!(parse("").is_err());
    assert!(parse("d").is_err());
}

#[test]
fn test_parse_whitespace_handling() {
    let expr = parse("  2d6 + 3  ").unwrap();
    assert_eq!(expr.count, 2);
}
