### Engine Tests (Seeded)

```rust
// tests/engine_test.rs
use sage_dice::engine::DiceEngine;
use sage_dice::parser::parse;

// Test seed: hash of "ImAttackingTheDarkness"
const TEST_SEED: u64 = 0x1A2B3C4D5E6F7890;

#[test]
fn test_seeded_deterministic() {
    let expr = parse("d20").unwrap();

    let mut engine1 = DiceEngine::with_seed(TEST_SEED);
    let mut engine2 = DiceEngine::with_seed(TEST_SEED);

    let result1 = engine1.roll(&expr).unwrap();
    let result2 = engine2.roll(&expr).unwrap();

    assert_eq!(result1.total, result2.total);
}

#[test]
fn test_roll_range() {
    let expr = parse("d20").unwrap();
    let mut engine = DiceEngine::new();

    for _ in 0..100 {
        let result = engine.roll(&expr).unwrap();
        assert!(result.total >= 1 && result.total <= 20);
    }
}

#[test]
fn test_roll_2d6_range() {
    let expr = parse("2d6").unwrap();
    let mut engine = DiceEngine::new();

    for _ in 0..100 {
        let result = engine.roll(&expr).unwrap();
        assert!(result.total >= 2 && result.total <= 12);
        assert_eq!(result.rolls.len(), 2);
    }
}

#[test]
fn test_modifier_applied() {
    let expr = parse("d20+5").unwrap();
    let mut engine = DiceEngine::with_seed(TEST_SEED);

    let result = engine.roll(&expr).unwrap();
    assert_eq!(result.modifier_total, 5);
    // total = roll + modifier
    assert_eq!(result.total, result.rolls[0] + 5);
}

#[test]
fn test_negative_modifier() {
    // D9: 1d6-100 → Allow negative totals
    let expr = parse("1d6-100").unwrap();
    let mut engine = DiceEngine::with_seed(TEST_SEED);

    let result = engine.roll(&expr).unwrap();
    assert!(result.total < 0);
    assert_eq!(result.modifier_total, -100);
}

#[test]
fn test_keep_highest() {
    let expr = parse("4d6kh3").unwrap();
    let mut engine = DiceEngine::with_seed(TEST_SEED);

    let result = engine.roll(&expr).unwrap();
    assert_eq!(result.rolls.len(), 4);
    assert_eq!(result.kept.len(), 3);
    assert_eq!(result.dropped.len(), 1);
    // Kept should be highest 3
    assert!(result.dropped[0] <= *result.kept.iter().min().unwrap());
}

#[test]
fn test_keep_more_than_rolled() {
    // D9: 4d6kh10 → Keep all 4
    let expr = parse("4d6kh10").unwrap();
    let mut engine = DiceEngine::with_seed(TEST_SEED);

    let result = engine.roll(&expr).unwrap();
    assert_eq!(result.rolls.len(), 4);
    assert_eq!(result.kept.len(), 4);
    assert_eq!(result.dropped.len(), 0);
}

#[test]
fn test_d1_always_one() {
    // D9: d1 always rolls 1
    let expr = parse("3d1").unwrap();
    let mut engine = DiceEngine::new();

    let result = engine.roll(&expr).unwrap();
    assert_eq!(result.rolls, vec![1, 1, 1]);
    assert_eq!(result.total, 3);
}
